private Path resolveExportLocation(String key) throws IOException {

        Path base = resourceBase.toAbsolutePath().normalize();
        Path target = base.resolve(key).resolve("report.txt").normalize();

        if (!target.startsWith(base)) {
            throw new IOException("Invalid report path");
        }

        return target;
    }
